        const __m256d p1r=_mm256_add_pd(t0r,t1r),p1i=_mm256_add_pd(t0i,t1i);
        const __m256d p2r=_mm256_sub_pd(t0r,t1r),p2i=_mm256_sub_pd(t0i,t1i);
        const __m256d qar=_mm256_fmadd_pd(cC,d2i,_mm256_mul_pd(cB,d1i)),qai=_mm256_fmadd_pd(cC,d2r,_mm256_mul_pd(cB,d1r));
